var f = this, d1 = f.getItemValue('ngay_ct'), d2 = f.getItemValue('ngay');
if (d1 < d2) {
  f._checked = false;
  $func.hideWait(f.get_id());
  $message.show(String.format($df.getResources(f._language, 'Message.RequiredField'), f.getItem('ngay_ct').field.Label), String.format('$find(\'{0}\').getItem(\'{1}\').focus()', f.get_id(), 'ngay_ct'));
}
