declare @field varchar(64), @message nvarchar(512)
exec rs_AutoGenerateStocktakingChecking @stt_rec, @ma_dvcs, @ma_kho, @type, @ngay_ct, @ma_kh, @tk, @ma_nx, @ma_quyen, 1, @field out, @message out, @@language, @@userID, @@admin, '@@sysDatabaseName'
if isnull(@message, '') <> '' begin
  select @field as field, @message as message, '' as script
  return
end

exec rs_AutoGenerateStocktaking @stt_rec, @ma_dvcs, @ma_kho, @type, @ngay_ct, @ma_kh, @dien_giai, @tk, @ma_nx, @ma_quyen, @status, 1, @field out, @message out, @@language, @@userID, @@admin, '@@sysDatabaseName'
if isnull(@message, '') <> '' begin
  select @field as field, @message as message, '' as script
  return
end
select '' as field, '' as message, 'on$AutoGenerateStocktakingCreate$QueryComplete(this);' as script
return







      &OutlineEntry;
      /* <flatten type="Javascript"> */
function load$AutoGenerateStocktakingCreate$(f) {
  var g = f.grid, v = (f._language == 'v'), o$ = f.getItem('status');

  f.add_onResponseComplete(on$AutoGenerateStocktakingCreate$ResponseComplete);
  f._looking = f.getItem('ma_quyen')._controlBehavior;
  f._looking.add_loading(on$AutoGenerateStocktakingCreate$Before$Loading);
  f.setItemValues('stt_rec, ma_dvcs, ma_kho, type', [g._$k, g._$u, g._$s, g._$t]);
  o$.options[1].text = (v ? ((g._$t == '1') ? '1. Xuất kho' : '1. Nhập kho') : ((g._$t == '1') ? '1. Issue' : '1. Receipt'));

  f.request('StocktakingCreate', 'StocktakingCreate', ['stt_rec', 'ma_dvcs', 'type']);
  f.getItem('ngay_ct').focus();
}
function dispose$AutoGenerateStocktakingCreate$(f) {
  try {f._looking.remove_loading(on$AutoGenerateStocktakingCreate$Before$Loading);} catch (ex) {}
  try {f.remove_onResponseComplete(on$AutoGenerateStocktakingCreate$ResponseComplete);} catch (ex) {}
}
function on$AutoGenerateStocktakingCreate$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'StocktakingCreate':
      f.setItemValues('ngay_ct, ngay', [result[0].Value, result[0].Value]);
      if (result[1]) {
        f.setItemValue('dien_giai', result[3].Value);
        f.setItemControlBehavior('ma_kh', result[1].Value, result[2].Value, true);
        f.setItemControlBehavior('tk', result[4].Value, result[5].Value, true);
        f.setItemControlBehavior('ma_nx', result[6].Value, result[7].Value, true);
      }
      break;
    default:
      break;
  }
}
function on$AutoGenerateStocktakingCreate$Before$Loading(sender, e) {
  var f = sender._element.parentForm;
  if (!f.validFields('ngay_ct')) e.type.cancelEvent = true;
  else {
    var g = f.grid, d = f.getItemValue('ngay_ct'), c = ((g._$t == '1') ? 'PXA' : 'PND');
    a = [
      {Name: 'd', Type: 'DateTime', Value: d},
      {Name: 'u', Type: 'String', Value: g._$u},
      {Name: 'c', Type: 'String', Value: c}
    ];
    sender.set_memvars(a);
  }
}
function on$AutoGenerateStocktakingCreate$QueryComplete(f) {
  var g = f.grid;
  g._formScript = 'show$AutoGenerateStocktakingCreate$QueryComplete(this)';
}
function show$AutoGenerateStocktakingCreate$QueryComplete(g) {
  var v = (g._language == 'v'), id = g.get_id();
  var e = (v ? 'Chương trình đã thực hiện xong.' : 'The process was completed successfully.');
  $message.show(e, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
  g._focusWhenTabChanged();
}
/* </flatten> */







declare @d smalldatetime
select @d = ngay_ct from kkyc where stt_rec = @stt_rec
if exists(select 1 from dmclkktd where ma_dvcs = @ma_dvcs) begin
  if @type = '1'
    select @d as ngay_ct, a.ma_kh_thieu, b.ten_kh%l, a.dien_giai_thieu, a.tk_kk_thieu, c.ten_tk%l, a.ma_nx_thieu, d.ten_nx%l
      from dmclkktd a
        left join dmkh b on a.ma_kh_thieu = b.ma_kh
        left join dmtk c on a.tk_kk_thieu = c.tk
        left join dmnx d on a.ma_nx_thieu = d.ma_nx
      where ma_dvcs = @ma_dvcs
  else
    select @d as ngay_ct, a.ma_kh_thua, b.ten_kh%l, a.dien_giai_thua, a.tk_kk_thua, c.ten_tk%l, a.ma_nx_thua, d.ten_nx%l
      from dmclkktd a
        left join dmkh b on a.ma_kh_thua = b.ma_kh
        left join dmtk c on a.tk_kk_thua = c.tk
        left join dmnx d on a.ma_nx_thua = d.ma_nx
      where ma_dvcs = @ma_dvcs
  return
end
select @d as ngay_ct
return





